// Attempt to get existing jobs from the flow context
let jobs = flow.get("jobs");

// If jobs don't exist yet, generate them dynamically
if (!jobs) {
    // 1. Define your list of meters with metadata (ID, name, location, etc.)
    const meters = [
        { id: 1, name: "meter_1", location: "B1 IT" }
    ]; 

    // 2. Define the common register configuration for this specific meter model
    const meterModelConfig = {
        fc: 3,
        address: 3203,
        quantity: 4,
        dataType: "uint64",
        wordOrder: "BE",
        scale: 1
    };

    // 3. Automatically map the meter objects to create the jobs array
    jobs = meters.map(meter => {
        return {
            name: `${meter.name}_PowerMeter`,
            unitid: meter.id,
            meterName: meter.name,    // Added metadata
            location: meter.location, // Added metadata
            ...meterModelConfig
        };
    });

    // Second model to push to the array
    jobs.push({
        name: "PowerMeter",
        fc: 3,
        unitid: 2,
        meterName: "IT DB", // Added metadata
        location: "B1 2ndFloor",      // Added metadata
        address: 999,
        quantity: 2,
        dataType: "float32",
        wordOrder: "BE",
        scale: 1
    });

    // Save to flow context so we only calculate this array once
    flow.set("jobs", jobs);
}

// Get the current index (default to 0 on first run)
let i = flow.get("job_index") || 0;
let job = jobs[i];

msg.job = job;

// Prepare payload for the Modbus Flex Getter node
msg.topic = job.name;
msg.payload = {
    fc: job.fc,
    unitid: job.unitid,
    address: job.address,
    quantity: job.quantity
};

// Increment index for the next inject interval, wrap around to 0 when reaching the end
flow.set("job_index", (i + 1) % jobs.length);

return msg;

// timestamp formatter
function getTimestamp() {
    let now = new Date();
    let yyyy = now.getFullYear();
    let mm = String(now.getMonth() + 1).padStart(2, '0');
    let dd = String(now.getDate()).padStart(2, '0');
    let hh = String(now.getHours()).padStart(2, '0');
    let min = String(now.getMinutes()).padStart(2, '0');
    let ss = String(now.getSeconds()).padStart(2, '0');
    return `${yyyy}-${mm}-${dd} ${hh}:${min}:${ss}`;
}

function swapWords16(arr) {
    if (!Array.isArray(arr) || arr.length < 2) return arr;
    let out = [];
    for (let i = 0; i < arr.length; i += 2) {
        if (i + 1 < arr.length) {
            out.push(arr[i + 1], arr[i]);
        } else {
            out.push(arr[i]);
        }
    }
    return out;
}

function regsToBuffer(regs) {
    const buf = Buffer.alloc(regs.length * 2);
    for (let i = 0; i < regs.length; i++) {
        buf.writeUInt16BE(regs[i] & 0xFFFF, i * 2);
    }
    return buf;
}

function toBigInt64FromRegs(regs, wordOrder) {
    let r = regs.slice();
    if (wordOrder === "LE") r = swapWords16(r);

    let value = 0n;
    for (let i = 0; i < r.length; i++) {
        value = (value << 16n) | BigInt(r[i] & 0xFFFF);
    }
    return value;
}

// get saved job
//let job = flow.get("current_job") || {};
let job = msg.job || {};
let regs = [];

if (msg.payload && Array.isArray(msg.payload.data)) {
    regs = msg.payload.data;
} else if (Array.isArray(msg.payload)) {
    regs = msg.payload;
} else {
    node.warn("No register array found in msg.payload.data");
    return null;
}

let dataType = (job.dataType || "").toLowerCase();
let wordOrder = job.wordOrder || "BE";
let scale = Number(job.scale || 1);
let value = null;

try {
    if (dataType === "float32") {
        let r = regs.slice(0, 2);
        if (wordOrder === "LE") r = swapWords16(r);
        let buf = regsToBuffer(r);
        value = buf.readFloatBE(0) * scale;

    } else if (dataType === "uint32") {
        let r = regs.slice(0, 2);
        if (wordOrder === "LE") r = swapWords16(r);
        let buf = regsToBuffer(r);
        value = buf.readUInt32BE(0) * scale;

    } else if (dataType === "int32") {
        let r = regs.slice(0, 2);
        if (wordOrder === "LE") r = swapWords16(r);
        let buf = regsToBuffer(r);
        value = buf.readInt32BE(0) * scale;

    } else if (dataType === "uint64") {
        let r = regs.slice(0, 4);
        let bigVal = toBigInt64FromRegs(r, wordOrder);
        value = Number(bigVal) * scale;

    } else if (dataType === "uint16") {
        value = (regs[0] || 0) * scale;

    } else if (dataType === "int16") {
        let v = regs[0] || 0;
        if (v > 32767) v = v - 65536;
        value = v * scale;

    } else if (dataType === "float64") {
        let r = regs.slice(0, 4);
        let buf = Buffer.alloc(8);
        buf.writeUInt16BE(r[3], 0);
        buf.writeUInt16BE(r[2], 2);
        buf.writeUInt16BE(r[1], 4);
        buf.writeUInt16BE(r[0], 6);
        value = buf.readDoubleBE(0) * scale;

    } else {
        value = regs;
    }

    msg.payload = {
        meter_id: job.meterName || null,
        location: job.location || null,
        dataout: value,
        timestamp: getTimestamp()
    };

    return msg;

} catch (err) {
    node.error("Conversion failed: " + err.message, msg);
    return null;
}
